/**
 * Send a notification through the appropriate adapter.
 * Creates a full NotificationPayload and delegates to the registered adapter.
 * Notifications for the same recipient are serialized to guarantee delivery order.
 */
async send(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority?: NotificationPriority;
  metadata?: Record<string, unknown>;
}): Promise<NotificationResult> {
  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    priority: params.priority ?? 'normal',
    createdAt: new Date(),
    metadata: params.metadata,
  };

  // Chain this send onto the recipient's queue to preserve ordering.
  const previous = this.sendQueues.get(params.recipient) ?? Promise.resolve(undefined as unknown as NotificationResult);
  const current = previous.then(() => this.deliverNotification(payload, params));
  this.sendQueues.set(params.recipient, current);

  return current;
}

/**
 * Internal delivery method — executes the actual send logic.
 * Called sequentially per recipient via the send queue.
 */
private async deliverNotification(
  payload: NotificationPayload,
  params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    metadata?: Record<string, unknown>;
  },
): Promise<NotificationResult> {
  // Check user preferences before sending (if a PreferencesService is attached).
  if (this.preferencesService) {
    const userId = (params.metadata?.userId as string) ?? params.recipient;
    if (!this.preferencesService.shouldSend(userId, params.channel, params.type)) {
      this.logger.info(
        `Notification suppressed by user preferences: ${params.type} via ${params.channel} for ${userId}`,
      );
      const result: NotificationResult = {
        success: true,
        notification: payload,
        deliveredAt: new Date(),
      };
      this.results.push(result);
      this.historyService?.logNotification(result, { suppressed: true });
      return result;
    }
  }

  const adapter = this.adapters.get(params.channel);
  if (!adapter) {
    this.logger.warn(`No adapter registered for channel: ${params.channel}`);
    const result: NotificationResult = {
      success: false,
      notification: payload,
      deliveredAt: new Date(),
      error: `No adapter registered for channel: ${params.channel}`,
    };
    this.results.push(result);
    this.historyService?.logNotification(result);
    return result;
  }

  this.logger.info(`Sending ${params.type} notification via ${params.channel} to ${params.recipient}`);

  const result = await adapter.send(payload);
  this.results.push(result);
  this.historyService?.logNotification(result);
  return result;
}

