  describe('notification ordering', () => {
    it('should deliver notifications in order when events fire concurrently for the same recipient', async () => {
      // Create a slow adapter that introduces variable delays to simulate real-world async delivery.
      const deliveryOrder: string[] = [];
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          // First notification takes longer to deliver than the second,
          // which would cause out-of-order delivery without queuing.
          const delay = payload.type === 'order-confirmation' ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return { success: true, notification: payload, deliveredAt: new Date() };
        },
      };

      service.registerAdapter(slowAdapter);

      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Fire both events concurrently — without queuing, the faster status-update
      // notification would be delivered before the slower order-confirmation.
      await Promise.all([
        eventBus.emit(orderCreatedEvent),
        eventBus.emit(statusChangedEvent),
      ]);

      // Order-confirmation (sent first) must be delivered before order-status-update.
      expect(deliveryOrder).toEqual(['order-confirmation', 'order-status-update']);

      const results = service.getResults();
      expect(results).toHaveLength(2);
      expect(results[0]?.notification.type).toBe('order-confirmation');
      expect(results[1]?.notification.type).toBe('order-status-update');
    });

    it('should not block notifications for different recipients', async () => {
      const deliveryOrder: string[] = [];
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as const,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
          // Alice's notification is slow, Bob's is fast.
          const delay = payload.recipient === 'alice@example.com' ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(`${payload.recipient}:${payload.type}`);
          return { success: true, notification: payload, deliveredAt: new Date() };
        },
      };

      service.registerAdapter(slowAdapter);

      // Send to two different recipients concurrently.
      const [aliceResult, bobResult] = await Promise.all([
        service.send({
          type: 'order-confirmation',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Alice Order',
          body: 'Your order',
        }),
        service.send({
          type: 'order-confirmation',
          channel: 'email',
          recipient: 'bob@example.com',
          subject: 'Bob Order',
          body: 'Your order',
        }),
      ]);

      expect(aliceResult.success).toBe(true);
      expect(bobResult.success).toBe(true);
      // Bob's notification should complete before Alice's since they're independent.
      expect(deliveryOrder[0]).toBe('bob@example.com:order-confirmation');
      expect(deliveryOrder[1]).toBe('alice@example.com:order-confirmation');
    });
  });
});

